const DICT_WORDS=[
  {id:1,tagalog:"Malungkot",alternatives:["Lungkot","Nakakalungkot"],pronunciation:"ma · lung · kot",partOfSpeech:"adjective",definition:"Feeling sadness, sorrow, or a deep sense of longing.",en:{translation:"Sad, lonely, melancholic",example:{tl:"Malungkot ako ngayon.",tr:"I am sad today."}},es:{translation:"Triste, melancólico",example:{tl:"Malungkot ako ngayon.",tr:"Estoy triste hoy."}},de:{translation:"Traurig, melancholisch",example:{tl:"Malungkot ako ngayon.",tr:"Ich bin heute traurig."}},culturalNote:"While 'malungkot' is the proper Tagalog word, most Filipinos in everyday conversation simply say 'sad' instead. You'll hear 'malungkot' more in songs and poetry — giving it a heartfelt quality when used in speech.",searchTerms:["sad","lonely","melancholic","triste","solo","traurig","einsam","malungkot","lungkot"]},
  {id:2,tagalog:"Masaya",alternatives:["Saya","Maligaya"],pronunciation:"ma · sa · ya",partOfSpeech:"adjective",definition:"Feeling happiness, joy, or delight — a lightness of heart.",en:{translation:"Happy, joyful, cheerful",example:{tl:"Masaya ako sa araw na ito!",tr:"I am happy today!"}},es:{translation:"Feliz, alegre, contento",example:{tl:"Masaya ako sa araw na ito!",tr:"¡Estoy feliz hoy!"}},de:{translation:"Glücklich, fröhlich",example:{tl:"Masaya ako sa araw na ito!",tr:"Ich bin heute glücklich!"}},culturalNote:"Filipinos are known for their resilience and joy — 'masaya' appears constantly in everyday speech. You'll often hear 'masaya!' as a standalone exclamation meaning 'how fun!'",searchTerms:["happy","joyful","cheerful","feliz","alegre","glücklich","fröhlich","masaya","saya"]},
  {id:3,tagalog:"Mahal",alternatives:["Pag-ibig","Pagmamahal"],pronunciation:"ma · hal",partOfSpeech:"adjective / verb",definition:"To love deeply; also means expensive — what you love is what you value most.",en:{translation:"Love / Expensive / Dear",example:{tl:"Mahal kita.",tr:"I love you."}},es:{translation:"Amor / Caro / Querido",example:{tl:"Mahal kita.",tr:"Te quiero."}},de:{translation:"Liebe / Teuer / Wertvoll",example:{tl:"Mahal kita.",tr:"Ich liebe dich."}},culturalNote:"'Mahal' means both 'love' and 'expensive'. This duality is deeply cultural: what you love is what you value most.",searchTerms:["love","expensive","dear","amor","caro","querido","liebe","teuer","mahal","pag-ibig"]},
  {id:4,tagalog:"Kumusta",alternatives:["Kamusta","Musta"],pronunciation:"ku · mus · ta",partOfSpeech:"greeting",definition:"A warm greeting asking how someone is doing; derived from the Spanish '¿Cómo estás?'",en:{translation:"How are you? / Hello",example:{tl:"Kumusta ka na?",tr:"How have you been?"}},es:{translation:"¿Cómo estás? / ¿Qué tal?",example:{tl:"Kumusta ka na?",tr:"¿Cómo has estado?"}},de:{translation:"Wie geht es dir? / Hallo",example:{tl:"Kumusta ka na?",tr:"Wie geht es dir?"}},culturalNote:"Kumusta is borrowed from Spanish '¿Cómo estás?' — a beautiful trace of the Philippines' colonial history. Casually shortened to 'musta?' in everyday speech.",searchTerms:["hello","how are you","hola","como estas","hallo","wie geht","kumusta","kamusta","musta"]},
  {id:5,tagalog:"Salamat",alternatives:["Maraming salamat","Salamat po"],pronunciation:"sa · la · mat",partOfSpeech:"expression",definition:"An expression of gratitude and deep appreciation.",en:{translation:"Thank you / Thanks",example:{tl:"Salamat sa lahat!",tr:"Thank you for everything!"}},es:{translation:"Gracias / Muchas gracias",example:{tl:"Salamat sa lahat!",tr:"¡Gracias por todo!"}},de:{translation:"Danke / Vielen Dank",example:{tl:"Salamat sa lahat!",tr:"Danke für alles!"}},culturalNote:"Adding 'po' signals deep respect toward elders. 'Maraming salamat' (many thanks) is the emphatic version. Gratitude is central to Filipino culture.",searchTerms:["thank you","thanks","gracias","danke","salamat","maraming salamat"]},
  {id:6,tagalog:"Gutom",alternatives:["Nagugutom","Gutom na gutom"],pronunciation:"gu · tom",partOfSpeech:"adjective",definition:"Feeling hungry; the physical state of needing food.",en:{translation:"Hungry / Starving",example:{tl:"Gutom na ko — kumain na tayo!",tr:"I'm hungry — let's eat!"}},es:{translation:"Hambriento / Con mucha hambre",example:{tl:"Gutom na ko — kumain na tayo!",tr:"¡Tengo hambre — vamos a comer!"}},de:{translation:"Hungrig / Ausgehungert",example:{tl:"Gutom na ko — kumain na tayo!",tr:"Ich habe Hunger — lass uns essen!"}},culturalNote:"Food is the heartbeat of Filipino culture — 'gutom ka na ba?' is practically a second greeting. Saying you're hungry in Filipino company means you will be fed, often insistently.",searchTerms:["hungry","hunger","starving","hambriento","hambre","hungrig","gutom","nagugutom"]},
  {id:7,tagalog:"Ingat",alternatives:["Mag-ingat","Pag-ingatan"],pronunciation:"i · ngat",partOfSpeech:"verb / expression",definition:"To take care; to be careful. Used as a warm farewell wishing someone safety.",en:{translation:"Take care / Be careful",example:{tl:"Ingat ka lagi!",tr:"Always take care of yourself!"}},es:{translation:"Cuídate / Ten cuidado",example:{tl:"Ingat ka lagi!",tr:"¡Cuídate siempre!"}},de:{translation:"Pass auf dich auf!",example:{tl:"Ingat ka lagi!",tr:"Pass immer auf dich auf!"}},culturalNote:"Saying 'ingat' when parting is so natural that many Filipino-Americans say it even in English. It's a reflex of care, not just a polite phrase.",searchTerms:["take care","careful","goodbye","cuídate","aufpassen","ingat","mag-ingat"]},
  {id:8,tagalog:"Bahala na",alternatives:["Bahala","Bahala na si Batman"],pronunciation:"ba · ha · la · na",partOfSpeech:"expression / philosophy",definition:"Leaving things to fate — a blend of courage, trust, and acceptance in the face of uncertainty.",en:{translation:"Leave it to fate / Come what may",example:{tl:"Nag-aral na ako — bahala na!",tr:"I've studied my best — come what may!"}},es:{translation:"Lo que sea / Que será, será",example:{tl:"Nag-aral na ako — bahala na!",tr:"¡Ya estudié — que será, será!"}},de:{translation:"Was sein soll, wird sein",example:{tl:"Nag-aral na ako — bahala na!",tr:"Ich habe mein Bestes gegeben — was sein soll, wird sein!"}},culturalNote:"Rooted in the pre-colonial deity 'Bathala', bahala na means 'I've done what I can — now I trust the universe.' The variant 'Bahala na si Batman' shows Filipinos defusing stress with humor.",searchTerms:["fate","destiny","whatever","lo que sea","schicksal","bahala na","bahala"]},
];

const LIT_WORDS=[
  {id:1,word:"Gigil",pronunciation:"gi · gil",teaser:"The urge to squeeze something unbearably cute",category:"Emotions",concept:"That specific, almost aggressive urge you feel when something is so cute you want to squeeze it. It's the physical, uncontrollable impulse that comes with overwhelming cuteness.",en:{closest:"No direct equivalent",explanation:"English has no single word for this. 'Cute aggression' is a term researchers coined recently — but it doesn't capture the physical urgency of gigil.",example:{tl:"Gigil na gigil ako sa kanya!",tr:"I just can't handle how cute he/she is!"}},es:{closest:"Sin equivalente directo",explanation:"El español tampoco tiene una palabra exacta. 'Me muero de lo lindo' se acerca pero no captura el impulso físico involuntario.",example:{tl:"Gigil na gigil ako sa kanya!",tr:"¡Me muero de lo lindo que es!"}},de:{closest:"Kein direktes Äquivalent",explanation:"'Knuddeln wollen' kommt vielleicht am nächsten, aber gigil ist ein unkontrollierbarer, überwältigender Impuls.",example:{tl:"Gigil na gigil ako sa kanya!",tr:"Ich kann nicht aufhören, ihn/sie knuddeln zu wollen!"}},culturalNote:"Gigil is one of the most universally relatable Filipino words. When shared with non-Filipinos, the reaction is almost always 'we NEED this word.' Psychologists coined 'cute aggression' in 2015. Filipinos had gigil centuries before that."},
  {id:2,word:"Kilig",pronunciation:"ki · lig",teaser:"The giddiness and butterflies of romantic excitement",category:"Emotions",concept:"The overwhelming feeling of romantic excitement and giddiness — triggered by a sweet gesture, a confession of love, or a tender moment. The delightful, almost embarrassing kind of thrill.",en:{closest:"Butterflies / Swooning",explanation:"'Butterflies in your stomach' comes close but kilig is more specific — the giddy joy of romantic excitement with a warm physical sensation.",example:{tl:"Kilig na kilig ako sa sinabi niya!",tr:"I got so giddy from what he/she said!"}},es:{closest:"Mariposas en el estómago",explanation:"'Mariposas en el estómago' se acerca pero kilig es la alegría romántica pura cuando alguien especial hace algo dulce.",example:{tl:"Kilig na kilig ako sa sinabi niya!",tr:"¡Me llenó de mariposas lo que dijo!"}},de:{closest:"Schmetterlinge im Bauch",explanation:"'Schmetterlinge im Bauch' kommt nah, aber kilig hat eine besondere romantische Freude bei etwas Süßem und Unerwartetem.",example:{tl:"Kilig na kilig ako sa sinabi niya!",tr:"Ich hatte totale Schmetterlinge von dem, was er/sie gesagt hat!"}},culturalNote:"Kilig is so embedded in Filipino pop culture that romance films are specifically designed to make audiences feel it. Filipinos say 'I'm kilig' even in English because no English word does the job."},
  {id:3,word:"Tampo",pronunciation:"tam · po",teaser:"Quietly withdrawing affection when your feelings are hurt",category:"Social",concept:"Gently withdrawing affection and attention — not out of anger, not out of sadness, but as a quiet signal that feelings have been hurt. Asking for care without asking for it.",en:{closest:"Sulking / Withdrawal",explanation:"'Sulking' carries a childish connotation that tampo doesn't deserve. In Filipino culture, tampo is a recognized form of communication — a way of saying 'you hurt me' without confrontation.",example:{tl:"Nagtatamapo siya dahil hindi siya naalala.",tr:"She/he is doing tampo because she/he wasn't remembered."}},es:{closest:"Hacer pucheros",explanation:"Tampo es un retiro afectivo silencioso y culturalmente aceptado — manera de decir 'me lastimaste' sin confrontación.",example:{tl:"Nagtatamapo siya dahil hindi siya naalala.",tr:"Está haciendo tampo porque no la/lo recordaron."}},de:{closest:"Schmollen",explanation:"'Schmollen' klingt kindischer. Tampo ist eine kulturell anerkannte indirekte Kommunikation ohne offene Konfrontation.",example:{tl:"Nagtatamapo siya dahil hindi siya naalala.",tr:"Er/sie schmollt, weil er/sie vergessen wurde."}},culturalNote:"Understanding tampo is key to understanding Filipino relationships. Direct confrontation is avoided — tampo is the socially accepted alternative. The right response is gentle attention, not logic."},
  {id:4,word:"Utang na loob",pronunciation:"u · tang · na · lo · ob",teaser:"A debt of gratitude so deep it shapes a lifetime",category:"Social",concept:"A profound sense of debt and gratitude toward someone who helped you — far deeper than thanks. It creates a moral obligation to reciprocate, sometimes for a lifetime.",en:{closest:"Debt of gratitude",explanation:"'Debt of gratitude' misses the weight entirely. Utang na loob can influence major life decisions — career, marriage, where to live — all to honor someone who once helped you.",example:{tl:"Malaki ang utang na loob ko sa kanya.",tr:"I owe him/her a tremendous debt of gratitude."}},es:{closest:"Deuda de gratitud",explanation:"La traducción no captura el peso moral. Utang na loob puede moldear decisiones de vida enteras.",example:{tl:"Malaki ang utang na loob ko sa kanya.",tr:"Le debo una enorme deuda de gratitud."}},de:{closest:"Dankesschuld",explanation:"'Dankesschuld' erfasst nicht das moralische Gewicht. Utang na loob kann ganze Lebensentscheidungen beeinflussen.",example:{tl:"Malaki ang utang na loob ko sa kanya.",tr:"Ich schulde ihm/ihr eine tiefe Dankbarkeit."}},culturalNote:"Utang na loob is one of the pillars of Filipino social structure. It's why Filipinos are fiercely loyal to those who helped them. To ignore it is considered a profound moral failure."},
  {id:5,word:"Diskarte",pronunciation:"dis · kar · te",teaser:"Street-smart creative problem-solving with what you have",category:"Everyday",concept:"A uniquely Filipino kind of resourcefulness — finding creative, improvised solutions using whatever is available. Practical ingenuity born from resilience and necessity.",en:{closest:"Resourcefulness / Street smarts",explanation:"'Street smarts' is close but misses the creative ingenuity of diskarte — solving problems others give up on through sheer Filipino adaptability.",example:{tl:"Kailangan mo ng diskarte dito!",tr:"You need to use your resourcefulness here!"}},es:{closest:"Ingenio / Picardía",explanation:"Diskarte es la habilidad práctica de resolver creativamente con lo que se tiene, especialmente donde otros se rendirían.",example:{tl:"Kailangan mo ng diskarte dito!",tr:"¡Aquí necesitas tu ingenio!"}},de:{closest:"Einfallsreichtum",explanation:"Diskarte ist kreative Problemlösung mit dem, was man hat, besonders dort, wo andere aufgeben.",example:{tl:"Kailangan mo ng diskarte dito!",tr:"Hier brauchst du deinen Einfallsreichtum!"}},culturalNote:"Diskarte represents the resilience Filipinos have developed through centuries of challenge. 'May diskarte siya' is a genuine compliment: this person knows how to navigate life."},
  {id:6,word:"Lihi",pronunciation:"li · hi",teaser:"A pregnant woman's experiences shape her unborn child",category:"Beliefs",concept:"A traditional Filipino belief that what a pregnant woman sees, eats, craves, or experiences during pregnancy will be reflected in the child — their appearance, personality, or talents.",en:{closest:"No direct equivalent",explanation:"English has no word for this. Lihi is alive and thriving in Filipino culture — shaping how communities surround pregnant women with care and positive experiences.",example:{tl:"Lihi raw siya sa mangga kaya matamis ang bata.",tr:"She supposedly craved mango, that's why the child is sweet-natured."}},es:{closest:"Sin equivalente directo",explanation:"Los 'antojos del embarazo' son lo más cercano, pero lihi va más allá — las experiencias de la madre moldean al bebé.",example:{tl:"Lihi raw siya sa mangga kaya matamis ang bata.",tr:"Dicen que se le antojó el mango, por eso el niño es de carácter dulce."}},de:{closest:"Kein direktes Äquivalent",explanation:"Lihi ist im philippinischen Alltag lebendig — es formt, wie Gemeinschaften schwangere Frauen mit Fürsorge umgeben.",example:{tl:"Lihi raw siya sa mangga kaya matamis ang bata.",tr:"Sie soll nach Mango verlangt haben — deshalb ist das Kind so sanftmütig."}},culturalNote:"Lihi is why Filipino families carefully surround pregnant women with beautiful things and kind people. It's one of many ways Filipino culture wraps pregnancy in communal care."},
  {id:7,word:"Bahala na",pronunciation:"ba · ha · la · na",teaser:"Leaving things to fate with courage, not resignation",category:"Philosophy",concept:"A uniquely Filipino attitude of leaving things to a higher power — not laziness, but a blend of courage, trust, and acceptance. I've done what I can. Now I trust the universe.",en:{closest:"Come what may",explanation:"'Come what may' captures the surface but misses the active courage. Bahala na is not passive resignation — it's deliberately choosing to release what you can't control.",example:{tl:"Nag-aral na ako nang husto — bahala na!",tr:"I've studied my best — come what may!"}},es:{closest:"Que será, será",explanation:"Bahala na tiene una valentía activa — no es resignación, es elegir conscientemente soltar lo que no puedes controlar.",example:{tl:"Nag-aral na ako nang husto — bahala na!",tr:"¡Ya estudié lo que pude — que sea lo que tenga que ser!"}},de:{closest:"Was sein soll, wird sein",explanation:"Bahala na hat einen aktiven Mut — es ist keine passive Resignation, sondern eine bewusste Entscheidung.",example:{tl:"Nag-aral na ako nang husto — bahala na!",tr:"Ich habe mein Bestes gelernt — was sein soll, wird sein!"}},culturalNote:"Rooted in the pre-colonial deity 'Bathala', bahala na is a survival philosophy. The modern variant 'Bahala na si Batman' shows Filipinos defusing stress with humor."},
  {id:8,word:"Hiya",pronunciation:"hi · ya",teaser:"Deep social shame tied to community harmony",category:"Social",concept:"More than embarrassment, hiya is a deep internalized sense of shame and social propriety — the awareness of how your actions reflect on your family and community.",en:{closest:"Shame / Embarrassment",explanation:"'Shame' is too heavy and 'embarrassment' too light. Hiya is the social awareness that keeps relationships smooth and faces saved.",example:{tl:"Wala siyang hiya!",tr:"He/she has no shame — no sense of propriety!"}},es:{closest:"Vergüenza / Pudor",explanation:"Hiya tiene una dimensión social más profunda — la conciencia de cómo tus acciones afectan a tu familia y comunidad.",example:{tl:"Wala siyang hiya!",tr:"¡No tiene vergüenza — ningún sentido de la decencia!"}},de:{closest:"Scham / Schicklichkeit",explanation:"Hiya ist das soziale Bewusstsein, das Beziehungen harmonisch hält und das Gesicht anderer wahrt.",example:{tl:"Wala siyang hiya!",tr:"Er/sie hat keine Scham — kein Gespür für Anstand!"}},culturalNote:"Hiya explains why Filipinos often avoid saying 'no' directly and why confrontation is rare. It's one of the core values shaping Filipino social behavior."},
];
const LIT_CATS=["All","Emotions","Social","Philosophy","Beliefs","Everyday"];

const PHRASES=[
  {id:1,phrase:"Tara na!",pronunciation:"ta · ra · na",theme:"Everyday",tagline:"Let's go — come on, let's head out!",howToUse:"Use this when you're ready to leave and want to bring someone along. It's casual, energetic, and almost always said with excitement.",en:{translation:"Let's go! / Come on!",example:{tl:"Tara na, gutom na ko!",tr:"Let's go, I'm already hungry!"}},es:{translation:"¡Vámonos! / ¡Anda ya!",example:{tl:"Tara na, gutom na ko!",tr:"¡Vámonos, ya tengo hambre!"}},de:{translation:"Lass uns gehen! / Komm schon!",example:{tl:"Tara na, gutom na ko!",tr:"Lass uns gehen, ich habe schon Hunger!"}},culturalTip:"Adding 'na' signals urgency in Tagalog — 'tara na' literally means 'let's go already.' You'll hear this constantly among Filipino friends."},
  {id:2,phrase:"Kumain ka na?",pronunciation:"ku · ma · in · ka · na",theme:"Food",tagline:"Have you eaten yet? — one of the most Filipino things to say",howToUse:"Used as both a genuine question and a form of caring. Asking if someone has eaten is a way of saying 'I care about you' in Filipino culture.",en:{translation:"Have you eaten yet?",example:{tl:"Kumain ka na? Wag kang magpagutom!",tr:"Have you eaten yet? Don't let yourself go hungry!"}},es:{translation:"¿Ya comiste?",example:{tl:"Kumain ka na? Wag kang magpagutom!",tr:"¿Ya comiste? ¡No te dejes pasar hambre!"}},de:{translation:"Hast du schon gegessen?",example:{tl:"Kumain ka na? Wag kang magpagutom!",tr:"Hast du schon gegessen? Lass dich nicht hungern!"}},culturalTip:"This is arguably one of the most Filipino phrases. Food is deeply tied to love — 'kumain ka na?' is essentially asking 'are you okay?'"},
  {id:3,phrase:"Mabuhay!",pronunciation:"ma · bu · hay",theme:"Greetings",tagline:"Welcome! / Long live! — the Filipino spirit in one word",howToUse:"Used as a warm welcome, a toast, or a celebratory cheer. It literally means 'to live' — wishing someone a long, full life.",en:{translation:"Welcome! / Long live! / Cheers!",example:{tl:"Mabuhay ang Pilipinas!",tr:"Long live the Philippines!"}},es:{translation:"¡Bienvenido! / ¡Viva! / ¡Salud!",example:{tl:"Mabuhay ang Pilipinas!",tr:"¡Viva Filipinas!"}},de:{translation:"Willkommen! / Es lebe! / Prost!",example:{tl:"Mabuhay ang Pilipinas!",tr:"Es lebe die Philippinen!"}},culturalTip:"Mabuhay greets you at every Philippine airport and hotel. Its literal meaning 'to live' makes it one of the most optimistic greetings in any language."},
  {id:4,phrase:"Ingat ka!",pronunciation:"i · ngat · ka",theme:"Everyday",tagline:"Take care — the Filipino way to say goodbye",howToUse:"Said when someone is leaving or ending a call. It's the most natural Filipino farewell — warmer than 'goodbye', more caring than 'see you later.'",en:{translation:"Take care! / Be safe!",example:{tl:"Ingat ka lagi sa daan!",tr:"Always take care on the road!"}},es:{translation:"¡Cuídate! / ¡Ten cuidado!",example:{tl:"Ingat ka lagi sa daan!",tr:"¡Cuídate siempre en el camino!"}},de:{translation:"Pass auf dich auf!",example:{tl:"Ingat ka lagi sa daan!",tr:"Pass immer auf dich auf unterwegs!"}},culturalTip:"Many Filipino-Americans say 'ingat ha!' even in English because no English farewell carries the same warmth. It's a reflex of care."},
  {id:5,phrase:"Mahal kita",pronunciation:"ma · hal · ki · ta",theme:"Emotions",tagline:"I love you — three words that carry enormous weight",howToUse:"Used to express deep love — romantic, familial, or close friendships. Because 'mahal' also means 'expensive', it carries the sense that the person is of great value.",en:{translation:"I love you",example:{tl:"Mahal na mahal kita.",tr:"I love you so very much."}},es:{translation:"Te quiero / Te amo",example:{tl:"Mahal na mahal kita.",tr:"Te quiero muchísimo."}},de:{translation:"Ich liebe dich",example:{tl:"Mahal na mahal kita.",tr:"Ich liebe dich so sehr."}},culturalTip:"Many Filipinos say 'I love you' in English for casual affection, reserving 'mahal kita' for when they truly mean it — the word carries more weight."},
  {id:6,phrase:"Kain na!",pronunciation:"ka · in · na",theme:"Food",tagline:"Let's eat! — the most joyful three syllables in Filipino",howToUse:"The call to come eat together. In Filipino culture, meals are communal — 'kain na!' signals that something good is happening and everyone should be part of it.",en:{translation:"Let's eat! / Food is ready!",example:{tl:"Kain na, luto na ang kanin!",tr:"Let's eat, the rice is cooked!"}},es:{translation:"¡A comer! / ¡Ya está la comida!",example:{tl:"Kain na, luto na ang kanin!",tr:"¡A comer, el arroz ya está listo!"}},de:{translation:"Essen! / Das Essen ist fertig!",example:{tl:"Kain na, luto na ang kanin!",tr:"Essen! Der Reis ist fertig!"}},culturalTip:"Being invited to eat with a Filipino family is one of the warmest gestures of acceptance. Food is how Filipinos express love, celebrate, and connect."},
  {id:7,phrase:"Magandang umaga!",pronunciation:"ma · gan · dang · u · ma · ga",theme:"Greetings",tagline:"Good morning — literally 'beautiful morning'",howToUse:"The standard Tagalog morning greeting. 'Maganda' means beautiful — every time-of-day greeting in Tagalog is a compliment to the moment.",en:{translation:"Good morning!",example:{tl:"Magandang umaga, kumain ka na ba?",tr:"Good morning, have you eaten yet?"}},es:{translation:"¡Buenos días!",example:{tl:"Magandang umaga, kumain ka na ba?",tr:"¡Buenos días, ya desayunaste?"}},de:{translation:"Guten Morgen!",example:{tl:"Magandang umaga, kumain ka na ba?",tr:"Guten Morgen, hast du schon gegessen?"}},culturalTip:"Filipino greetings for morning, noon, and evening all translate as 'beautiful [time of day].' Filipinos greet the world with beauty built into the language."},
  {id:8,phrase:"Sige na!",pronunciation:"si · ge · na",theme:"Everyday",tagline:"Come on! / Go ahead! — Tagalog's most versatile phrase",howToUse:"Can mean 'okay go ahead', 'please!', 'come on!', or 'fine, I give in.' Tone does all the work — playful with a smile, reluctant with a sigh.",en:{translation:"Go ahead! / Come on! / Fine, okay!",example:{tl:"Sige na, samahan mo ako!",tr:"Come on, come with me!"}},es:{translation:"¡Anda ya! / ¡Venga! / ¡Bueno!",example:{tl:"Sige na, samahan mo ako!",tr:"¡Venga, acompáñame!"}},de:{translation:"Na los! / Komm schon! / Na gut!",example:{tl:"Sige na, samahan mo ako!",tr:"Komm schon, begleite mich!"}},culturalTip:"Borrowed from Spanish 'sigue'. On its own, 'sige' means 'okay.' Adding 'na' intensifies it into pleading, urging, or reluctant agreement."},
];
const PHRASE_THEMES=["All","Greetings","Food","Emotions","Everyday"];

const PIL_ENTRIES=[
  {id:1,title:"Adobo",subtitle:"Pambansang Ulam · National Dish",category:"Food",image:"https://picsum.photos/seed/adobochicken/600/320",description:"The undisputed national dish of the Philippines — chicken or pork slow-braised in vinegar, soy sauce, garlic, bay leaves, and black pepper. Every Filipino family has their own version, and every version is the correct one.",facts:[{tl:"Niluto sa suka, toyo, bawang, at dahon ng laurel",en:"Cooked in vinegar, soy sauce, garlic & bay leaves",es:"Cocinado en vinagre, soja, ajo y laurel",de:"Gekocht in Essig, Sojasoße, Knoblauch & Lorbeer"},{tl:"Tatlong pangunahing uri: Manok, Baboy, at Flakes",en:"Three main types: Chicken, Pork, and Flakes",es:"Tres tipos: Pollo, Cerdo y Tiras",de:"Drei Varianten: Hähnchen, Schwein und Flakes"}],vocabulary:[{word:"suka",en:"vinegar",es:"vinagre",de:"Essig"},{word:"toyo",en:"soy sauce",es:"salsa de soja",de:"Sojasoße"},{word:"bawang",en:"garlic",es:"ajo",de:"Knoblauch"},{word:"laurel",en:"bay leaf",es:"laurel",de:"Lorbeerblatt"}],culturalNote:"Ask any Filipino what their mother's adobo tastes like and watch their eyes light up. Every family has their own secret recipe. Adobo is not just a dish; it's a family heirloom."},
  {id:2,title:"Sinigang",subtitle:"Maasim na Sabaw · Sour Broth",category:"Food",image:"https://picsum.photos/seed/sinigangsoup/600/320",description:"A tangy tamarind-based soup loaded with vegetables and protein. Its signature sourness makes it the ultimate Filipino comfort food, especially on rainy days.",facts:[{tl:"Ang sampalok ang nagbibigay ng asim sa sabaw",en:"Tamarind gives the broth its signature sourness",es:"El tamarindo le da al caldo su acidez",de:"Tamarinde verleiht der Brühe ihre Säure"},{tl:"Pinakamasarap kainin kapag maulan",en:"Best enjoyed on cold and rainy days",es:"Mejor en días fríos y lluviosos",de:"Am besten an kalten Tagen"}],vocabulary:[{word:"sabaw",en:"broth / soup",es:"caldo / sopa",de:"Brühe / Suppe"},{word:"sampalok",en:"tamarind",es:"tamarindo",de:"Tamarinde"},{word:"asim",en:"sourness",es:"acidez",de:"Säure"},{word:"gulay",en:"vegetables",es:"verduras",de:"Gemüse"}],culturalNote:"Sinigang consistently ranks as the top Filipino dish in international polls. For Filipinos abroad, a bowl of sinigang is homesickness in liquid form."},
  {id:3,title:"Lechon",subtitle:"Hari ng Pagkain · King of Feasts",category:"Food",image:"https://picsum.photos/seed/lechonroast/600/320",description:"A whole roasted pig, slow-cooked over charcoal until the skin is impossibly crispy and the meat falls off the bone. The crown jewel of every Filipino celebration.",facts:[{tl:"Luto nang maraming oras sa uling para maging malutong ang balat",en:"Roasted for hours over charcoal for perfectly crispy skin",es:"Asado durante horas sobre carbón para piel crujiente",de:"Stundenlang über Holzkohle geröstet"},{tl:"Ang Cebu ay kilala sa pinakamainam na lechon",en:"Cebu is renowned for the best lechon in the Philippines",es:"Cebú es famosa por el mejor lechón",de:"Cebu ist für das beste Lechon bekannt"}],vocabulary:[{word:"litson",en:"roasted / lechon",es:"asado / lechón",de:"Spanferkel"},{word:"balat",en:"skin / crust",es:"piel / cuero",de:"Haut / Kruste"},{word:"uling",en:"charcoal",es:"carbón",de:"Holzkohle"},{word:"salo-salo",en:"feast / gathering",es:"festín / reunión",de:"Fest"}],culturalNote:"A whole lechon at the center of a table signals abundance, celebration, and love. Anthony Bourdain once called it 'the best pig I've ever had.' Every Filipino nodded and said — of course."},
  {id:4,title:"Bayanihan",subtitle:"Diwa ng Pagkakaisa · Spirit of Unity",category:"Culture",image:"https://picsum.photos/seed/communitywork/600/320",description:"The ancient Filipino tradition of communal unity — neighbors coming together to help one another without expectation of payment.",facts:[{tl:"Nagmula sa salitang 'bayan' — komunidad o bansa",en:"Comes from 'bayan' — meaning community or nation",es:"Viene de 'bayan' — comunidad o nación",de:"Kommt von 'bayan' — Gemeinschaft oder Nation"},{tl:"Dati, tinutulungan ng mga kapitbahay na ilipat ang bahay",en:"Traditionally, neighbors literally carried a house together to move it",es:"Tradicionalmente, los vecinos cargaban una casa juntos",de:"Traditionell trugen Nachbarn ein Haus gemeinsam"}],vocabulary:[{word:"bayan",en:"community / nation",es:"comunidad / nación",de:"Gemeinschaft"},{word:"kapitbahay",en:"neighbor",es:"vecino",de:"Nachbar"},{word:"tulong",en:"help",es:"ayuda",de:"Hilfe"},{word:"sama-sama",en:"together",es:"juntos",de:"zusammen"}],culturalNote:"Bayanihan is the spirit that defines the Filipino response to disaster. When typhoons hit, Filipinos mobilize without being asked — instinctively, not organizationally."},
  {id:5,title:"Pasko",subtitle:"Pinakamahaba · World's Longest Christmas",category:"Culture",image:"https://picsum.photos/seed/christmaslights/600/320",description:"The Philippines celebrates the longest Christmas season in the world — starting in September and lasting through January. Christmas here is not just a holiday; it's a way of life.",facts:[{tl:"Nagsisimula ang Pasko sa Pilipinas sa buwan ng Setyembre",en:"Christmas in the Philippines starts in September",es:"La Navidad en Filipinas comienza en septiembre",de:"Weihnachten auf den Philippinen beginnt im September"},{tl:"Ang parol ay simbolo ng Pasko sa Pilipinas",en:"The parol (star lantern) is the symbol of Filipino Christmas",es:"El parol (farol) es el símbolo de la Navidad filipina",de:"Der Parol ist das Symbol des philippinischen Weihnachtsfests"}],vocabulary:[{word:"pasko",en:"Christmas",es:"Navidad",de:"Weihnachten"},{word:"parol",en:"star lantern",es:"farol de estrella",de:"Sternlaterne"},{word:"noche buena",en:"Christmas Eve feast",es:"Nochebuena",de:"Heiligabendfest"},{word:"simbang gabi",en:"dawn Mass",es:"Misa de Gallo",de:"Morgenmesse"}],culturalNote:"Filipino Christmas is a sensory experience — the smell of bibingka at dawn Mass, glowing parols in every window, carols starting in September. For Filipinos abroad, it's the holiday that makes homesickness most acute."},
  {id:6,title:"Videoke",subtitle:"Paboritong Libangan · Beloved Pastime",category:"Activities",image:"https://picsum.photos/seed/karaokenight/600/320",description:"Karaoke — or 'videoke' as Filipinos call it — is a social institution, a bonding ritual, and occasionally a competitive sport. No Filipino gathering is complete without it.",facts:[{tl:"Ginagawa ang videoke sa lahat ng okasyon",en:"Videoke happens at every occasion — fiestas, birthdays, ordinary evenings",es:"El videoke ocurre en toda ocasión",de:"Videoke findet bei jeder Gelegenheit statt"},{tl:"Ang My Way ni Frank Sinatra ay paboritong kanta",en:"My Way by Frank Sinatra is one of the most beloved videoke songs",es:"My Way es una de las canciones más queridas",de:"My Way ist eines der beliebtesten Videoke-Lieder"}],vocabulary:[{word:"videoke",en:"karaoke machine",es:"videoke / karaoke",de:"Karaoke-Maschine"},{word:"kanta",en:"song / to sing",es:"canción / cantar",de:"Lied / singen"},{word:"mikropono",en:"microphone",es:"micrófono",de:"Mikrofon"},{word:"saya",en:"fun / happiness",es:"diversión / alegría",de:"Spaß / Freude"}],culturalNote:"The Philippine love for videoke is so profound that machines are found in remote barangays with no running water but somehow a functioning karaoke setup. Filipinos don't need to sing well to sing passionately."},
];
const PIL_CATS=[{key:"All",tl:"Lahat",icon:"🇵🇭"},{key:"Food",tl:"Pagkain",icon:"🍽️"},{key:"Culture",tl:"Kultura",icon:"🎭"},{key:"Activities",tl:"Aktibidad",icon:"🎉"}];

const VALUES=[
  {icon:"🌺",title:"Genuine",tl:"Tunay",description:"Every word, every cultural note, every example comes from real Filipino life — not from a textbook or an algorithm."},
  {icon:"🤝",title:"For Everyone",tl:"Para sa Lahat",description:"Whether you're learning Tagalog, reconnecting with your roots, or simply curious — this place was made for you."},
  {icon:"🌍",title:"Multilingual",tl:"Maraming Wika",description:"Filipino culture deserves to be shared beyond English. Every entry speaks to Spanish and German speakers too."},
  {icon:"💛",title:"Free Always",tl:"Laging Libre",description:"Knowledge about Filipino language and culture should be accessible to everyone. This platform will always be free."},
];

const SP_MARKS=["feliz","triste","amor","gracias","hola","como","hambriento","cuídate","cuidate","querido","alegre"];
const DE_MARKS=["glücklich","glucklich","traurig","liebe","danke","hallo","hungrig","aufpassen","fröhlich","einsam"];
function detectLang(q){const ql=q.toLowerCase();if(SP_MARKS.some(m=>ql.includes(m)))return"es";if(DE_MARKS.some(m=>ql.includes(m)))return"de";return"en";}
function searchDict(q,wordList){const ql=q.toLowerCase().trim();if(!ql)return[];return (wordList||DICT_WORDS).filter(w=>w.tagalog.toLowerCase().includes(ql)||w.alternatives.some(a=>a.toLowerCase().includes(ql))||w.searchTerms.some(t=>t.toLowerCase().includes(ql))||w.definition.toLowerCase().includes(ql));}

function Nav({current,navigate}){
  const[hov,setHov]=useState(null);
  const items=[{key:"dictionary",label:"Dictionary",color:TEAL,ul:TEAL},{key:"tagalog101",label:"Tagalog 101",color:GOLD_DARK,ul:GOLD},{key:"lost",label:"Lost in Translation",color:TEAL,ul:TEAL},{key:"pilipinas",label:"Pilipinas",color:BROWN,ul:AMBER},{key:"about",label:"About",color:AMBER,ul:AMBER}];
  return(
    <nav style={{background:"rgba(255,251,243,0.97)",backdropFilter:"blur(12px)",borderBottom:`1px solid ${LIGHT_BORDER}`,padding:"0 40px",display:"flex",alignItems:"center",justifyContent:"space-between",height:"64px",position:"sticky",top:0,zIndex:100}}>
      <div onClick={()=>navigate("home")} style={{display:"flex",alignItems:"center",gap:"10px",cursor:"pointer"}}><span style={{fontSize:"22px"}}>🇵🇭</span><span style={{fontFamily:"'Baloo 2', cursive",fontWeight:800,fontSize:"20px",color:DARK}}>Wikang Filipino</span></div>
      <div style={{display:"flex",gap:"32px"}}>
        {items.map(({key,label,color,ul})=>(<span key={key} onClick={()=>navigate(key)} onMouseEnter={()=>setHov(key)} onMouseLeave={()=>setHov(null)} style={{fontSize:"14px",fontWeight:current===key?700:600,color:current===key?color:hov===key?DARK:MID,cursor:"pointer",borderBottom:current===key?`2px solid ${ul}`:"2px solid transparent",paddingBottom:"2px",transition:"color 0.15s"}}>{label}</span>))}
      </div>
    </nav>
  );
}

