          <div style={{background:NAVY_LIGHT,borderRadius:"20px",padding:"28px",marginBottom:"16px",border:"1px solid rgba(252,209,22,0.12)"}}><div style={{display:"flex",alignItems:"center",gap:"8px",marginBottom:"12px"}}><span style={{fontSize:"16px"}}>✏️</span><span style={{fontSize:"11px",fontWeight:700,color:GOLD,letterSpacing:"1.8px",textTransform:"uppercase"}}>Paano gamitin · How to use it</span></div><p style={{fontFamily:"'Nunito', sans-serif",fontSize:"15px",color:"rgba(255,255,255,0.78)",lineHeight:1.75}}>{sel.howToUse}</p></div>
